class User extends Model
{
    use HasFactory, SoftDeletes;

    protected $fillable = ['name', 'email', 'role', 'organization_id'];
    protected $hidden   = ['password', 'remember_token'];
    protected $casts    = ['is_active' => 'boolean', 'settings' => 'array'];

    // Scope: User::active()->role('admin')->get()
    public function scopeActive($query) { return $query->where('is_active', true); }
    public function scopeRole($query, string $role) { return $query->where('role', $role); }

    // Attribute API (Laravel 9+)
    protected function email(): Attribute
    {
        return Attribute::make(set: fn (string $v) => strtolower($v));
    }

    // Relationship
    public function organization(): BelongsTo { return $this->belongsTo(Organization::class); }
}

// app/Models/Concerns/Searchable.php
trait Searchable
{
    public function scopeSearch($query, ?string $term)
    {
        if (empty($term)) return $query;
        $columns = $this->searchable ?? ['name'];
        return $query->where(function ($q) use ($columns, $term) {
            foreach ($columns as $column) {
                $q->orWhere($column, 'ILIKE', "%{$term}%");
            }
        });
    }
}

class UserService
{
    public function __construct(
        private UserRepository $repository,
        private NotificationService $notifications,
    ) {}

    public function create(CreateUserDTO $dto): User
    {
        $user = DB::transaction(function () use ($dto) {
            return $this->repository->create([
                'name'            => $dto->name,
                'email'           => $dto->email,
                'password'        => Hash::make($dto->password),
                'organization_id' => $dto->organizationId,
            ]);
        });

        // Side effects OUTSIDE transaction
        event(new UserCreated($user));
        $this->notifications->sendWelcome($user);

        return $user;
    }
}

// Form Request converts validated input to a DTO
public function toDTO(): CreateUserDTO
{
    return new CreateUserDTO(
        name:           $this->validated('name'),
        email:          $this->validated('email'),
        password:       $this->validated('password'),
        organizationId: $this->user()->organization_id,
    );
}

interface UserRepositoryInterface
{
    public function find(int $id): ?User;
    public function paginate(array $filters = [], int $perPage = 15): LengthAwarePaginator;
    public function create(array $data): User;
    public function update(User $user, array $data): bool;
    public function delete(User $user): bool;
}

class CreateUserRequest extends FormRequest
{
    public function authorize(): bool
    {
        return $this->user()->can('create', User::class);
    }

    public function rules(): array
    {
        return [
            'name'     => ['required', 'string', 'min:2', 'max:100'],
            'email'    => ['required', 'email', Rule::unique('users')
                ->where('organization_id', $this->user()->organization_id)],
            'password' => ['required', Password::defaults()],
            'role'     => ['sometimes', Rule::in(['admin', 'moderator', 'member'])],
        ];
    }

    public function toDTO(): CreateUserDTO
    {
        return new CreateUserDTO(
            name: $this->validated('name'),
            email: $this->validated('email'),
            password: $this->validated('password'),
            organizationId: $this->user()->organization_id,
        );
    }
}

class UserResource extends JsonResource
{
    public function toArray(Request $request): array
    {
        return [
            'id'           => $this->id,
            'name'         => $this->name,
            'email'        => $this->email,
            'role'         => $this->role,
            'created_at'   => $this->created_at->toIso8601String(),
            'organization' => new OrganizationResource($this->whenLoaded('organization')),
            'settings'     => $this->when($request->user()?->id === $this->id, $this->settings),
        ];
    }
}

class UserController extends Controller
{
    public function __construct(private UserService $userService)
    {
        $this->authorizeResource(User::class);
    }

    public function store(CreateUserRequest $request): JsonResponse
    {
        $user = $this->userService->create($request->toDTO());
        return (new UserResource($user))->response()->setStatusCode(201);
    }

    public function destroy(User $user): JsonResponse
    {
        $this->userService->delete($user);
        return response()->json(null, 204);
    }
}

uses(RefreshDatabase::class);

beforeEach(function () {
    $this->organization = Organization::factory()->create();
    $this->admin = User::factory()->for($this->organization)->create(['role' => 'admin']);
});

it('can create a user', function () {
    $response = $this->actingAs($this->admin)->postJson('/api/v1/users', [
        'name' => 'Jane Doe', 'email' => 'jane@example.com', 'password' => 'SecurePass123!',
    ]);
    $response->assertCreated()->assertJsonPath('data.email', 'jane@example.com');
    $this->assertDatabaseHas('users', ['email' => 'jane@example.com']);
});

it('validates unique email within organization', function () {
    User::factory()->for($this->organization)->create(['email' => 'taken@example.com']);
    $this->actingAs($this->admin)->postJson('/api/v1/users', [
        'name' => 'Test', 'email' => 'taken@example.com', 'password' => 'SecurePass123!',
    ])->assertUnprocessable()->assertJsonValidationErrors(['email']);
});
